-- Mega Challenges Batch 1 (20 High-Quality Real World Challenges)
INSERT INTO sql_challenges (slug, title, difficulty, category, description, table_schema, seed_data, solution_sql, hint, order_sensitive, sort_order)
VALUES 
-- 1
('find-customers-in-london', 'Customers in London', 'easy', 'filtering', 'Find all customers who are located in London.', 'CREATE TABLE customers (id INT, name TEXT, city TEXT);', 'INSERT INTO customers VALUES (1, ''John'', ''London''), (2, ''Jane'', ''Paris''), (3, ''Bob'', ''London'');', 'SELECT * FROM customers WHERE city = ''London'';', 'Use a WHERE clause to filter by city.', false, 51),
-- 2
('calculate-total-revenue', 'Total Revenue', 'easy', 'aggregate', 'Calculate the total revenue generated from all orders.', 'CREATE TABLE orders (id INT, revenue DECIMAL);', 'INSERT INTO orders VALUES (1, 150.50), (2, 200.00), (3, 50.25);', 'SELECT SUM(revenue) FROM orders;', 'Use the SUM() aggregate function.', false, 52),
-- 3
('products-out-of-stock', 'Out of Stock Products', 'easy', 'filtering', 'List the names of products that have a stock of 0.', 'CREATE TABLE products (id INT, name TEXT, stock INT);', 'INSERT INTO products VALUES (1, ''Apple'', 10), (2, ''Banana'', 0), (3, ''Cherry'', 0);', 'SELECT name FROM products WHERE stock = 0;', 'Filter where stock equals 0.', false, 53),
-- 4
('it-department-employees', 'IT Department Employees', 'easy', 'joins', 'Find the names of all employees working in the IT department.', 'CREATE TABLE employees (id INT, name TEXT, dept_id INT); CREATE TABLE departments (id INT, name TEXT);', 'INSERT INTO departments VALUES (1, ''IT''), (2, ''HR''); INSERT INTO employees VALUES (1, ''Alice'', 1), (2, ''Bob'', 2), (3, ''Charlie'', 1);', 'SELECT e.name FROM employees e JOIN departments d ON e.dept_id = d.id WHERE d.name = ''IT'';', 'Join employees and departments, then filter by department name.', false, 54),
-- 5
('employees-per-department', 'Employees per Department', 'medium', 'aggregate', 'Count the number of employees in each department. Show the department name and the count. Include departments with no employees.', 'CREATE TABLE employees (id INT, name TEXT, dept_id INT); CREATE TABLE departments (id INT, name TEXT);', 'INSERT INTO departments VALUES (1, ''IT''), (2, ''HR''), (3, ''Sales''); INSERT INTO employees VALUES (1, ''Alice'', 1), (2, ''Bob'', 2), (3, ''Charlie'', 1), (4, ''Dave'', 1);', 'SELECT d.name, COUNT(e.id) FROM departments d LEFT JOIN employees e ON d.id = e.dept_id GROUP BY d.name;', 'Use LEFT JOIN to include departments with 0 employees, and GROUP BY department name.', false, 55),
-- 6
('users-with-no-posts', 'Users with No Posts', 'medium', 'joins', 'Find the usernames of users who have never made a post.', 'CREATE TABLE users (id INT, username TEXT); CREATE TABLE posts (id INT, user_id INT, content TEXT);', 'INSERT INTO users VALUES (1, ''user1''), (2, ''user2''), (3, ''user3''); INSERT INTO posts VALUES (1, 1, ''Hello''), (2, 1, ''World'');', 'SELECT u.username FROM users u LEFT JOIN posts p ON u.id = p.user_id WHERE p.id IS NULL;', 'Use LEFT JOIN and check for NULL post IDs.', false, 56),
-- 7
('most-liked-post', 'Most Liked Post', 'medium', 'aggregate', 'Find the content of the post with the highest number of likes.', 'CREATE TABLE posts (id INT, content TEXT, likes INT);', 'INSERT INTO posts VALUES (1, ''First post'', 10), (2, ''Second post'', 50), (3, ''Third post'', 20);', 'SELECT content FROM posts ORDER BY likes DESC LIMIT 1;', 'Order by likes in descending order and limit the result to 1.', false, 57),
-- 8
('high-value-transactions', 'High Value Transactions', 'easy', 'filtering', 'Find all transactions with an amount greater than 1000.', 'CREATE TABLE transactions (id INT, amount DECIMAL, tx_date DATE);', 'INSERT INTO transactions VALUES (1, 500, ''2023-01-01''), (2, 1500, ''2023-01-02''), (3, 2000, ''2023-01-03'');', 'SELECT * FROM transactions WHERE amount > 1000;', 'Use WHERE amount > 1000.', false, 58),
-- 9
('total-spent-per-user', 'Total Spent per User', 'medium', 'aggregate', 'Calculate the total amount spent by each user. Display user_id and total_spent.', 'CREATE TABLE purchases (id INT, user_id INT, amount DECIMAL);', 'INSERT INTO purchases VALUES (1, 1, 50), (2, 1, 150), (3, 2, 200);', 'SELECT user_id, SUM(amount) as total_spent FROM purchases GROUP BY user_id;', 'Group by user_id and SUM the amount.', false, 59),
-- 10
('patients-older-than-60', 'Senior Patients', 'easy', 'filtering', 'Find the names of patients who are older than 60.', 'CREATE TABLE patients (id INT, name TEXT, age INT);', 'INSERT INTO patients VALUES (1, ''John'', 45), (2, ''Mary'', 65), (3, ''Tom'', 70);', 'SELECT name FROM patients WHERE age > 60;', 'Filter by age > 60.', false, 60),
-- 11
('doctor-patient-count', 'Patients per Doctor', 'medium', 'aggregate', 'Count how many patients each doctor is treating. Show doctor name and patient count.', 'CREATE TABLE doctors (id INT, name TEXT); CREATE TABLE patients (id INT, name TEXT, doc_id INT);', 'INSERT INTO doctors VALUES (1, ''Dr. Smith''), (2, ''Dr. Jones''); INSERT INTO patients VALUES (1, ''P1'', 1), (2, ''P2'', 1), (3, ''P3'', 2);', 'SELECT d.name, COUNT(p.id) FROM doctors d LEFT JOIN patients p ON d.id = p.doc_id GROUP BY d.name;', 'Join doctors and patients, group by doctor name.', false, 61),
-- 12
('pending-deliveries', 'Pending Deliveries', 'easy', 'filtering', 'List the tracking numbers of deliveries that are marked as ''Pending''.', 'CREATE TABLE deliveries (id INT, tracking_no TEXT, status TEXT);', 'INSERT INTO deliveries VALUES (1, ''TRK123'', ''Delivered''), (2, ''TRK456'', ''Pending''), (3, ''TRK789'', ''Pending'');', 'SELECT tracking_no FROM deliveries WHERE status = ''Pending'';', 'Filter by status = ''Pending''.', false, 62),
-- 13
('average-delivery-days', 'Average Delivery Days', 'medium', 'aggregate', 'Calculate the average number of days it takes for a delivery to be completed. Use delivery_date - order_date.', 'CREATE TABLE deliveries (id INT, order_date DATE, delivery_date DATE);', 'INSERT INTO deliveries VALUES (1, ''2023-01-01'', ''2023-01-05''), (2, ''2023-01-10'', ''2023-01-12'');', 'SELECT AVG(delivery_date - order_date) FROM deliveries;', 'Subtract order_date from delivery_date inside the AVG function.', false, 63),
-- 14
('students-without-grades', 'Students without Grades', 'medium', 'joins', 'Find the names of students who have not received any grades yet.', 'CREATE TABLE students (id INT, name TEXT); CREATE TABLE grades (student_id INT, course_id INT, grade TEXT);', 'INSERT INTO students VALUES (1, ''Alice''), (2, ''Bob''); INSERT INTO grades VALUES (1, 101, ''A'');', 'SELECT s.name FROM students s LEFT JOIN grades g ON s.id = g.student_id WHERE g.grade IS NULL;', 'Use LEFT JOIN and check where grade IS NULL.', false, 64),
-- 15
('highest-grade-per-class', 'Highest Grade per Class', 'hard', 'window', 'Find the student ID with the highest score in each class. If there is a tie, return all top students for that class.', 'CREATE TABLE scores (student_id INT, class_id INT, score INT);', 'INSERT INTO scores VALUES (1, 101, 95), (2, 101, 80), (3, 101, 95), (4, 102, 88), (5, 102, 90);', 'WITH ranked AS (SELECT student_id, class_id, RANK() OVER(PARTITION BY class_id ORDER BY score DESC) as rnk FROM scores) SELECT student_id, class_id FROM ranked WHERE rnk = 1;', 'Use RANK() partitioned by class_id and ordered by score descending.', false, 65),
-- 16
('top-selling-product', 'Top Selling Product', 'hard', 'aggregate', 'Find the product name that has the highest total quantity sold.', 'CREATE TABLE products (id INT, name TEXT); CREATE TABLE sales (product_id INT, quantity INT);', 'INSERT INTO products VALUES (1, ''A''), (2, ''B''); INSERT INTO sales VALUES (1, 10), (1, 5), (2, 20);', 'SELECT p.name FROM products p JOIN sales s ON p.id = s.product_id GROUP BY p.id, p.name ORDER BY SUM(s.quantity) DESC LIMIT 1;', 'Group by product, SUM quantity, order descending, and limit 1.', false, 66),
-- 17
('salary-above-department-avg', 'Salary Above Dept Average', 'hard', 'subquery', 'Find employees who earn more than the average salary of their own department. Show employee name, salary, and department id.', 'CREATE TABLE employees (id INT, name TEXT, salary INT, dept_id INT);', 'INSERT INTO employees VALUES (1, ''A'', 5000, 1), (2, ''B'', 7000, 1), (3, ''C'', 4000, 2), (4, ''D'', 8000, 2);', 'SELECT name, salary, dept_id FROM employees e1 WHERE salary > (SELECT AVG(salary) FROM employees e2 WHERE e1.dept_id = e2.dept_id);', 'Use a correlated subquery.', false, 67),
-- 18
('mutual-friends', 'Mutual Friends', 'hard', 'joins', 'Find the count of mutual friends between user 1 and user 2.', 'CREATE TABLE friends (user_id INT, friend_id INT);', 'INSERT INTO friends VALUES (1, 3), (1, 4), (2, 3), (2, 5), (1, 5);', 'SELECT COUNT(*) FROM (SELECT friend_id FROM friends WHERE user_id = 1 INTERSECT SELECT friend_id FROM friends WHERE user_id = 2) AS mutual;', 'Use INTERSECT to find common friend_ids, then COUNT them.', false, 68),
-- 19
('moving-average-3-days', '3-Day Moving Average', 'hard', 'window', 'Calculate the 3-day moving average of sales for each date.', 'CREATE TABLE daily_sales (sale_date DATE, amount INT);', 'INSERT INTO daily_sales VALUES (''2023-01-01'', 10), (''2023-01-02'', 20), (''2023-01-03'', 30), (''2023-01-04'', 40);', 'SELECT sale_date, amount, AVG(amount) OVER (ORDER BY sale_date ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) as moving_avg FROM daily_sales;', 'Use AVG() OVER (...) with ROWS BETWEEN 2 PRECEDING AND CURRENT ROW.', true, 69),
-- 20
('delivery-route-overlap', 'Delivery Route Overlap', 'hard', 'joins', 'Find pairs of truck IDs (truck_a, truck_b where truck_a < truck_b) that visited the same city on the same date.', 'CREATE TABLE route_logs (truck_id INT, city TEXT, visit_date DATE);', 'INSERT INTO route_logs VALUES (1, ''NY'', ''2023-01-01''), (2, ''NY'', ''2023-01-01''), (1, ''LA'', ''2023-01-02''), (3, ''LA'', ''2023-01-02'');', 'SELECT DISTINCT a.truck_id as truck_a, b.truck_id as truck_b FROM route_logs a JOIN route_logs b ON a.city = b.city AND a.visit_date = b.visit_date WHERE a.truck_id < b.truck_id;', 'Self-join the route_logs table on city and visit_date.', false, 70)
ON CONFLICT (slug) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    table_schema = EXCLUDED.table_schema,
    seed_data = EXCLUDED.seed_data,
    solution_sql = EXCLUDED.solution_sql,
    hint = EXCLUDED.hint;
